```cpp
#include <iostream>
#include <vector>

// n번째 숫자를 계산하는 함수
int findNthNumber(int n) {
    // 초기 세 숫자 설정
    if (n == 1) return 0;
    if (n == 2) return -1;
    if (n == 3) return -1;

    // 숫자를 저장할 벡터 초기화
    std::vector<int> sequence = {0, -1, -1};

    // 4번째 숫자부터 n번째 숫자까지 계산
    for (int i = 4; i <= n; ++i) {
        // 이전 세 숫자의 합을 계산하여 다음 숫자 결정
        int nextNumber = sequence[i-1] + sequence[i-2] + sequence[i-3];
        sequence.push_back(nextNumber);
    }

    // n번째 숫자 반환
    return sequence[n - 1]; // 인덱스 조정
}

int main() {
    int n;
    std::cout << "몇 번째 숫자를 구할까요? (n 입력): ";
    std::cin >> n;

    // 입력 검증: n이 0일 경우 예외 처리
    if (n < 1) {
        std::cout << "양수를 입력해주세요." << std::endl;
    } else {
        int result = findNthNumber(n);
        std::cout << "해당 수열의 " << n << "번째 숫자는 " << result << "입니다." << std::endl;
    }

    return 0;
}
